arguments.file_text:
namespace sv_af87f0a772e94f2bbe31ecf917acd1cb.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

namespace sv_af87f0a772e94f2bbe31ecf917acd1cb.Services;

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

.chat-layout {
    height: 100vh;
    width: 100vw;
    overflow: hidden;
    margin: 0;
    padding: 0;
}

@namespace sv_af87f0a772e94f2bbe31ecf917acd1cb.Components.Chat

<div class="channel-list">
    <div class="channel-list-header">
        <h5>Channels</h5>
    </div>
    <div class="channel-items">
        @if (Channels is not null)
        {
            @foreach (var channel in Channels)
            {
                <div class="channel-item @(channel.Id == ActiveChannelId ? "active" : "")"
                     @onclick="() => OnChannelSelected.InvokeAsync(channel.Id)">
                    <div class="channel-name-row">
                        <span class="channel-name"># @channel.Name</span>
                        @if (channel.UnreadCount > 0)
                        {
                            <span class="unread-badge">@channel.UnreadCount</span>
                        }
                    </div>
                    @if (!string.IsNullOrWhiteSpace(channel.Description))
                    {
                        <div class="channel-description">@Truncate(channel.Description, 50)</div>
                    }
                </div>
            }
        }
    </div>
</div>

@code {
    [Parameter] public List<Channel>? Channels { get; set; }
    [Parameter] public int ActiveChannelId { get; set; }
    [Parameter] public EventCallback<int> OnChannelSelected { get; set; }

    private static string Truncate(string text, int maxLength) =>
        text.Length <= maxLength ? text : text[..maxLength] + "…";
}

.channel-list {
    display: flex;
    flex-direction: column;
    height: 100%;
    background-color: #2c2f33;
    color: #dcddde;
}

.channel-list-header {
    padding: 16px;
    border-bottom: 1px solid #23272a;
}

.channel-list-header h5 {
    margin: 0;
    font-size: 1rem;
    text-transform: uppercase;
    letter-spacing: 0.05em;
    color: #8e9297;
}

.channel-items {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
}

.channel-item {
    padding: 8px 16px;
    cursor: pointer;
    border-radius: 4px;
    margin: 0 8px;
    transition: background-color 0.15s;
}

.channel-item:hover {
    background-color: #36393f;
}

.channel-item.active {
    background-color: #40444b;
    color: #fff;
}

.channel-name-row {
    display: flex;
    align-items: center;
    justify-content: space-between;
}

.channel-name {
    font-weight: 500;
    font-size: 0.95rem;
}

.unread-badge {
    background-color: #ed4245;
    color: #fff;
    border-radius: 10px;
    padding: 1px 7px;
    font-size: 0.75rem;
    font-weight: 700;
    min-width: 18px;
    text-align: center;
}

.channel-description {
    font-size: 0.8rem;
    color: #72767d;
    margin-top: 2px;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

@namespace sv_af87f0a772e94f2bbe31ecf917acd1cb.Components.Chat

<div class="emoji-picker">
    @foreach (var emoji in _emojis)
    {
        <button class="emoji-btn" @onclick="() => OnEmojiSelected.InvokeAsync(emoji)"
                @onclick:stopPropagation="true" title="@emoji">
            @emoji
        </button>
    }
</div>

@code {
    [Parameter] public EventCallback<string> OnEmojiSelected { get; set; }

    private static readonly string[] _emojis = ["👍", "❤️", "😂", "🎉", "😮", "😢"];
}

.emoji-picker {
    display: flex;
    gap: 4px;
    background: #2c2f33;
    border: 1px solid #40444b;
    border-radius: 6px;
    padding: 6px 8px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.3);
    position: absolute;
    bottom: 100%;
    right: 0;
    margin-bottom: 4px;
    z-index: 10;
}

.emoji-btn {
    background: none;
    border: none;
    cursor: pointer;
    font-size: 1.2rem;
    padding: 4px 6px;
    border-radius: 4px;
    transition: background-color 0.15s;
    line-height: 1;
}

.emoji-btn:hover {
    background-color: #40444b;
}

@namespace sv_af87f0a772e94f2bbe31ecf917acd1cb.Components.Chat

<div class="message-item" @onmouseenter="() => _hovered = true" @onmouseleave="OnMouseLeave">
    <div class="message-header">
        <span class="message-author">@Message.Author</span>
        <span class="message-time">@FormatRelativeTime(Message.SentAt)</span>
    </div>
    <div class="message-content">@Message.Content</div>

    @if (Message.Reactions.Count > 0)
    {
        <div class="message-reactions">
            @foreach (var reaction in Message.Reactions)
            {
                <span class="reaction-badge" title="@string.Join(", ", reaction.Users)"
                      @onclick="() => OnReact.InvokeAsync(reaction.Emoji)">
                    @reaction.Emoji @reaction.Users.Count
                </span>
            }
        </div>
    }

    @if (ThreadReplyCount > 0)
    {
        <button class="thread-link" @onclick="() => OnOpenThread.InvokeAsync(Message.Id)">
            @ThreadReplyCount @(ThreadReplyCount == 1 ? "reply" : "replies")
        </button>
    }

    @if (_hovered)
    {
        <div class="message-actions">
            <button class="action-btn" @onclick="() => OnOpenThread.InvokeAsync(Message.Id)" title="Reply in thread">
                💬
            </button>
            <div class="react-action-wrapper" style="position: relative;">
                <button class="action-btn" @onclick="ToggleEmojiPicker" @onclick:stopPropagation="true" title="Add reaction">
                    😀
                </button>
                @if (_showEmojiPicker)
                {
                    <EmojiPicker OnEmojiSelected="HandleEmojiSelected" />
                }
            </div>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public Message Message { get; set; } = default!;
    [Parameter] public int ThreadReplyCount { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<string> OnReact { get; set; }

    private bool _hovered;
    private bool _showEmojiPicker;

    private void OnMouseLeave()
    {
        _hovered = false;
        _showEmojiPicker = false;
    }

    private void ToggleEmojiPicker() => _showEmojiPicker = !_showEmojiPicker;

    private async Task HandleEmojiSelected(string emoji)
    {
        _showEmojiPicker = false;
        await OnReact.InvokeAsync(emoji);
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();

        if (diff.TotalSeconds < 60) return "just now";
        if (diff.TotalMinutes < 60)
            return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24)
            return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7)
            return $"{(int)diff.TotalDays}d ago";

        return sentAt.ToString("MMM d, yyyy");
    }
}

.message-item {
    padding: 8px 16px;
    position: relative;
    border-radius: 4px;
    transition: background-color 0.1s;
}

.message-item:hover {
    background-color: #32353b;
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.message-author {
    font-weight: 600;
    color: #fff;
    font-size: 0.95rem;
}

.message-time {
    font-size: 0.75rem;
    color: #72767d;
}

.message-content {
    color: #dcddde;
    font-size: 0.9rem;
    line-height: 1.4;
    white-space: pre-wrap;
    word-break: break-word;
}

.message-reactions {
    display: flex;
    gap: 4px;
    margin-top: 4px;
    flex-wrap: wrap;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    background: #2c2f33;
    border: 1px solid #40444b;
    border-radius: 12px;
    padding: 2px 8px;
    font-size: 0.8rem;
    cursor: pointer;
    color: #dcddde;
    transition: background-color 0.15s;
}

.reaction-badge:hover {
    background-color: #40444b;
}

.thread-link {
    background: none;
    border: none;
    color: #00aff4;
    font-size: 0.8rem;
    cursor: pointer;
    padding: 4px 0;
    margin-top: 2px;
    font-weight: 500;
}

.thread-link:hover {
    text-decoration: underline;
}

.message-actions {
    position: absolute;
    top: -12px;
    right: 16px;
    display: flex;
    gap: 2px;
    background: #2c2f33;
    border: 1px solid #40444b;
    border-radius: 4px;
    padding: 2px;
    box-shadow: 0 1px 4px rgba(0, 0, 0, 0.2);
}

.action-btn {
    background: none;
    border: none;
    cursor: pointer;
    font-size: 1rem;
    padding: 4px 8px;
    border-radius: 3px;
    line-height: 1;
    transition: background-color 0.15s;
}

.action-btn:hover {
    background-color: #40444b;
}

.react-action-wrapper {
    position: relative;
    display: inline-flex;
}

@using Microsoft.JSInterop
@namespace sv_af87f0a772e94f2bbe31ecf917acd1cb.Components.Chat
@inject IJSRuntime JS

<div class="message-area">
    <div class="message-area-header">
        @if (Channel is not null)
        {
            <h5># @Channel.Name</h5>
            <span class="channel-desc">@Channel.Description</span>
        }
    </div>

    <div class="message-list" @ref="_messageListRef" @onscroll="HandleScroll">
        @if (IsLoadingMore)
        {
            <div class="loading-indicator">Loading older messages…</div>
        }
        @if (Messages is not null)
        {
            @foreach (var msg in Messages)
            {
                <MessageItem Message="msg"
                             ThreadReplyCount="GetThreadReplyCount(msg.Id)"
                             OnOpenThread="OnOpenThread"
                             OnReact="(emoji) => OnReact.InvokeAsync((msg.Id, emoji))" />
            }
        }
    </div>

    <div class="message-input-area">
        <textarea class="message-textarea" @bind="NewMessageText" @bind:event="oninput"
                  @onkeydown="HandleKeyDown"
                  placeholder="@($"Message #{Channel?.Name ?? "channel"}")"
                  rows="1"></textarea>
        <button class="send-btn" @onclick="SendMessage" disabled="@string.IsNullOrWhiteSpace(NewMessageText)">
            Send
        </button>
    </div>
</div>

@code {
    [Parameter] public Channel? Channel { get; set; }
    [Parameter] public List<Message>? Messages { get; set; }
    [Parameter] public Dictionary<int, int>? ThreadReplyCounts { get; set; }
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
    [Parameter] public EventCallback<string> OnSendMessage { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }

    private ElementReference _messageListRef;
    private string NewMessageText { get; set; } = "";
    private int? _previousMessageCount;
    private int? _previousChannelId;

    private int GetThreadReplyCount(int messageId) =>
        ThreadReplyCounts?.GetValueOrDefault(messageId) ?? 0;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        var currentCount = Messages?.Count ?? 0;
        var currentChannelId = Channel?.Id;

        // Scroll to bottom on channel change or new message sent
        if (currentChannelId != _previousChannelId ||
            (_previousMessageCount is not null && currentCount > _previousMessageCount && !IsLoadingMore))
        {
            await ScrollToBottom();
        }

        _previousMessageCount = currentCount;
        _previousChannelId = currentChannelId;
    }

    private async Task ScrollToBottom()
    {
        try
        {
            await JS.InvokeVoidAsync("chatInterop.scrollToBottom", _messageListRef);
        }
        catch (JSException) { }
    }

    private async Task HandleScroll()
    {
        try
        {
            var scrollTop = await JS.InvokeAsync<double>("chatInterop.getScrollTop", _messageListRef);
            if (scrollTop <= 1 && !IsLoadingMore)
            {
                await OnLoadMore.InvokeAsync();
            }
        }
        catch (JSException) { }
    }

    private async Task HandleKeyDown(Microsoft.AspNetCore.Components.Web.KeyboardEventArgs e)
    {
        if (e.Key == "Enter" && !e.ShiftKey)
        {
            await SendMessage();
        }
    }

    private async Task SendMessage()
    {
        var text = NewMessageText?.Trim();
        if (string.IsNullOrWhiteSpace(text)) return;
        NewMessageText = "";
        await OnSendMessage.InvokeAsync(text);
    }
}

