{"path": "/tmp/sv-af87f0a772e94f2bbe31ecf917acd1cb/Components/Chat/ThreadPanel.razor", "file_text": "@namespace sv_af87f0a772e94f2bbe31ecf917acd1cb.Components.Chat

<div class="thread-panel">
    <div class="thread-header">
        <h5>Thread</h5>
        <button class="close-btn" @onclick="OnClose" title="Close thread">✕</button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-root-message">
            <div class="thread-root-author">@RootMessage.Author</div>
            <div class="thread-root-content">@RootMessage.Content</div>
        </div>
    }

    <div class="thread-divider">
        <span>@(Replies?.Count ?? 0) @(Replies?.Count == 1 ? "reply" : "replies")</span>
    </div>

    <div class="thread-replies">
        @if (Replies is not null)
        {
            @foreach (var reply in Replies)
            {
                <div class="thread-reply">
                    <div class="reply-header">
                        <span class="reply-author">@reply.Author</span>
                        <span class="reply-time">@FormatRelativeTime(reply.SentAt)</span>
                    </div>
                    <div class="reply-content">@reply.Content</div>
                </div>
            }
        }
    </div>

    <div class="thread-input-area">
        <textarea class="thread-textarea" @bind="ReplyText" @bind:event="oninput"
                  @onkeydown="HandleKeyDown"
                  placeholder="Reply…" rows="1"></textarea>
        <button class="reply-btn" @onclick="SendReply" disabled="@string.IsNullOrWhiteSpace(ReplyText)">
            Reply
        </button>
    </div>
</div>

@code {
    [Parameter] public Message? RootMessage { get; set; }
    [Parameter] public List<Message>? Replies { get; set; }
    [Parameter] public EventCallback OnClose { get; set; }
    [Parameter] public EventCallback<string> OnSendReply { get; set; }

    private string ReplyText { get; set; } = "";

    private async Task HandleKeyDown(Microsoft.AspNetCore.Components.Web.KeyboardEventArgs e)
    {
        if (e.Key == "Enter" && !e.ShiftKey)
        {
            await SendReply();
        }
    }

    private async Task SendReply()
    {
        var text = ReplyText?.Trim();
        if (string.IsNullOrWhiteSpace(text)) return;
        ReplyText = "";
        await OnSendReply.InvokeAsync(text);
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();
        if (diff.TotalSeconds < 60) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }
}
"}

