.message-item {
    padding: 8px 16px;
    position: relative;
    border-radius: 4px;
    transition: background-color 0.1s;
}

.message-item:hover {
    background-color: #32353b;
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.message-author {
    font-weight: 600;
    color: #fff;
    font-size: 0.95rem;
}

.message-time {
    font-size: 0.75rem;
    color: #72767d;
}

.message-content {
    color: #dcddde;
    font-size: 0.9rem;
    line-height: 1.4;
    white-space: pre-wrap;
    word-break: break-word;
}

.message-reactions {
    display: flex;
    gap: 4px;
    margin-top: 4px;
    flex-wrap: wrap;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    background: #2c2f33;
    border: 1px solid #40444b;
    border-radius: 12px;
    padding: 2px 8px;
    font-size: 0.8rem;
    cursor: pointer;
    color: #dcddde;
    transition: background-color 0.15s;
}

.reaction-badge:hover {
    background-color: #40444b;
}

.thread-link {
    background: none;
    border: none;
    color: #00aff4;
    font-size: 0.8rem;
    cursor: pointer;
    padding: 4px 0;
    margin-top: 2px;
    font-weight: 500;
}

.thread-link:hover {
    text-decoration: underline;
}

.message-actions {
    position: absolute;
    top: -12px;
    right: 16px;
    display: flex;
    gap: 2px;
    background: #2c2f33;
    border: 1px solid #40444b;
    border-radius: 4px;
    padding: 2px;
    box-shadow: 0 1px 4px rgba(0, 0, 0, 0.2);
}

.action-btn {
    background: none;
    border: none;
    cursor: pointer;
    font-size: 1rem;
    padding: 4px 8px;
    border-radius: 3px;
    line-height: 1;
    transition: background-color 0.15s;
}

.action-btn:hover {
    background-color: #40444b;
}

.react-action-wrapper {
    position: relative;
    display: inline-flex;
}

