    <div class="message-list" @ref="_messageListRef" @onscroll="HandleScroll">
        @if (IsLoadingMore)
        {
            <div class="loading-indicator">Loading older messages…</div>
        }
        @if (Messages is not null)
        {
            @foreach (var msg in Messages)
            {
                <MessageItem Message="msg"
                             ThreadReplyCount="GetThreadReplyCount(msg.Id)"
                             OnOpenThread="OnOpenThread"
                             OnReact="(emoji) => OnReact.InvokeAsync((msg.Id, emoji))" />
            }
        }
    </div>

    <div class="message-input-area">
        <textarea class="message-textarea" @bind="NewMessageText" @bind:event="oninput"
                  @onkeydown="HandleKeyDown"
                  placeholder="@($"Message #{Channel?.Name ?? "channel"}")"
                  rows="1"></textarea>
        <button class="send-btn" @onclick="SendMessage" disabled="@string.IsNullOrWhiteSpace(NewMessageText)">
            Send
        </button>
    </div>
</div>

@code {
    [Parameter] public Channel? Channel { get; set; }
    [Parameter] public List<Message>? Messages { get; set; }
    [Parameter] public Dictionary<int, int>? ThreadReplyCounts { get; set; }
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
    [Parameter] public EventCallback<string> OnSendMessage { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }

    private ElementReference _messageListRef;
    private string NewMessageText { get; set; } = "";
    private int? _previousMessageCount;
    private int? _previousChannelId;

    private int GetThreadReplyCount(int messageId) =>
        ThreadReplyCounts?.GetValueOrDefault(messageId) ?? 0;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        var currentCount = Messages?.Count ?? 0;
        var currentChannelId = Channel?.Id;

        // Scroll to bottom on channel change or new message sent
        if (currentChannelId != _previousChannelId ||
            (_previousMessageCount is not null && currentCount > _previousMessageCount && !IsLoadingMore))
        {
            await ScrollToBottom();
        }

        _previousMessageCount = currentCount;
        _previousChannelId = currentChannelId;
    }

    private async Task ScrollToBottom()
    {
        try
        {
            await JS.InvokeVoidAsync("chatInterop.scrollToBottom", _messageListRef);
        }
        catch (JSException) { }
    }

    private async Task HandleScroll()
    {
        try
        {
            var scrollTop = await JS.InvokeAsync<double>("chatInterop.getScrollTop", _messageListRef);
            if (scrollTop <= 1 && !IsLoadingMore)
            {
                await OnLoadMore.InvokeAsync();
            }
        }
        catch (JSException) { }
    }

    private async Task HandleKeyDown(Microsoft.AspNetCore.Components.Web.KeyboardEventArgs e)
    {
        if (e.Key == "Enter" && !e.ShiftKey)
        {
            await SendMessage();
        }
    }

    private async Task SendMessage()
    {
        var text = NewMessageText?.Trim();
        if (string.IsNullOrWhiteSpace(text)) return;
        NewMessageText = "";
        await OnSendMessage.InvokeAsync(text);
    }
}

