.message-area {
    display: flex;
    flex-direction: column;
    height: 100%;
    background-color: #36393f;
}

.message-area-header {
    padding: 12px 16px;
    border-bottom: 1px solid #23272a;
    display: flex;
    align-items: baseline;
    gap: 12px;
    flex-shrink: 0;
}

.message-area-header h5 {
    margin: 0;
    color: #fff;
    font-size: 1rem;
    font-weight: 700;
}

.channel-desc {
    color: #72767d;
    font-size: 0.85rem;
}

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
    display: flex;
    flex-direction: column;
}

.loading-indicator {
    text-align: center;
    padding: 12px;
    color: #72767d;
    font-size: 0.85rem;
}

.message-input-area {
    padding: 8px 16px 16px;
    flex-shrink: 0;
    display: flex;
    gap: 8px;
    align-items: flex-end;
}

.message-textarea {
    flex: 1;
    background: #40444b;
    border: none;
    border-radius: 8px;
    color: #dcddde;
    padding: 10px 14px;
    font-size: 0.9rem;
    resize: none;
    min-height: 40px;
    max-height: 120px;
    font-family: inherit;
    outline: none;
}

.message-textarea::placeholder {
    color: #72767d;
}

.message-textarea:focus {
    box-shadow: 0 0 0 1px #5865f2;
}

.send-btn {
    background: #5865f2;
    color: #fff;
    border: none;
    border-radius: 8px;
    padding: 10px 20px;
    font-size: 0.9rem;
    font-weight: 600;
    cursor: pointer;
    transition: background-color 0.15s;
    white-space: nowrap;
}

.send-btn:hover:not(:disabled) {
    background: #4752c4;
}

.send-btn:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

