.thread-panel {
    display: flex;
    flex-direction: column;
    height: 100%;
    background-color: #36393f;
    border-left: 1px solid #23272a;
}

.thread-header {
    padding: 12px 16px;
    border-bottom: 1px solid #23272a;
    display: flex;
    align-items: center;
    justify-content: space-between;
    flex-shrink: 0;
}

.thread-header h5 {
    margin: 0;
    color: #fff;
    font-size: 1rem;
    font-weight: 700;
}

.close-btn {
    background: none;
    border: none;
    color: #b9bbbe;
    font-size: 1.1rem;
    cursor: pointer;
    padding: 4px 8px;
    border-radius: 4px;
    transition: background-color 0.15s, color 0.15s;
    line-height: 1;
}

.close-btn:hover {
    background-color: #40444b;
    color: #fff;
}

.thread-root-message {
    padding: 12px 16px;
    border-bottom: 1px solid #2c2f33;
    background-color: #32353b;
    flex-shrink: 0;
}

.thread-root-author {
    font-weight: 600;
    color: #fff;
    font-size: 0.9rem;
    margin-bottom: 4px;
}

.thread-root-content {
    color: #dcddde;
    font-size: 0.85rem;
    line-height: 1.4;
    white-space: pre-wrap;
    word-break: break-word;
}

.thread-divider {
    padding: 8px 16px;
    font-size: 0.75rem;
    color: #72767d;
    border-bottom: 1px solid #2c2f33;
    flex-shrink: 0;
}

.thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 4px 0;
}

.thread-reply {
    padding: 8px 16px;
}

.reply-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.reply-author {
    font-weight: 600;
    color: #fff;
    font-size: 0.85rem;
}

.reply-time {
    font-size: 0.7rem;
    color: #72767d;
}

.reply-content {
    color: #dcddde;
    font-size: 0.85rem;
    line-height: 1.4;
    white-space: pre-wrap;
    word-break: break-word;
}

.thread-input-area {
    padding: 8px 12px 12px;
    flex-shrink: 0;
    display: flex;
    gap: 8px;
    align-items: flex-end;
}

.thread-textarea {
    flex: 1;
    background: #40444b;
    border: none;
    border-radius: 8px;
    color: #dcddde;
    padding: 8px 12px;
    font-size: 0.85rem;
    resize: none;
    min-height: 36px;
    max-height: 100px;
    font-family: inherit;
    outline: none;
}

.thread-textarea::placeholder {
    color: #72767d;
}

.thread-textarea:focus {
    box-shadow: 0 0 0 1px #5865f2;
}

.reply-btn {
    background: #5865f2;
    color: #fff;
    border: none;
    border-radius: 8px;
    padding: 8px 16px;
    font-size: 0.85rem;
    font-weight: 600;
    cursor: pointer;
    transition: background-color 0.15s;
    white-space: nowrap;
}

.reply-btn:hover:not(:disabled) {
    background: #4752c4;
}

.reply-btn:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

