@page "/chat"
@layout ChatLayout
@using sv_af87f0a772e94f2bbe31ecf917acd1cb.Services
@using sv_af87f0a772e94f2bbe31ecf917acd1cb.Components.Chat
@rendermode InteractiveServer
@inject IChatService ChatService

<PageTitle>Team Chat</PageTitle>

<div class="chat-container">
    <div class="chat-sidebar">
        <ChannelList Channels="_channels"
                     ActiveChannelId="_activeChannelId"
                     OnChannelSelected="SelectChannel" />
    </div>

    <div class="chat-main @(IsThreadOpen ? "" : "chat-main-expanded")">
        <MessageArea Channel="_activeChannel"
                     Messages="_messages"
                     ThreadReplyCounts="_threadReplyCounts"
                     IsLoadingMore="_isLoadingMore"
                     OnOpenThread="OpenThread"
                     OnReact="HandleReaction"
                     OnSendMessage="SendMessage"
                     OnLoadMore="LoadOlderMessages" />
    </div>

    @if (IsThreadOpen)
    {
        <div class="chat-thread">
            <ThreadPanel RootMessage="_threadRootMessage"
                         Replies="_threadReplies"
                         OnClose="CloseThread"
                         OnSendReply="SendThreadReply" />
        </div>
    }
</div>

@code {
    private const int PageSize = 30;

    private List<Channel>? _channels;
    private int _activeChannelId;
    private Channel? _activeChannel;
    private List<Message> _messages = new();
    private Dictionary<int, int> _threadReplyCounts = new();
    private int _skip;
    private bool _isLoadingMore;
    private bool _hasMoreMessages = true;

    // Thread state
    private Message? _threadRootMessage;
    private List<Message>? _threadReplies;
    private bool IsThreadOpen => _threadRootMessage is not null;

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
        if (_channels?.Count > 0)
        {
            await SelectChannel(_channels[0].Id);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        if (_activeChannelId == channelId) return;

        _activeChannelId = channelId;
        _activeChannel = _channels?.FirstOrDefault(c => c.Id == channelId);
        _skip = 0;
        _hasMoreMessages = true;
        _messages = new();
        _threadRootMessage = null;
        _threadReplies = null;

        var msgs = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        _messages = msgs;
        _skip = msgs.Count;

        await ChatService.MarkChannelReadAsync(channelId);
        await RefreshThreadCounts();
        await RefreshChannels();
    }

    private async Task LoadOlderMessages()
    {
        if (_isLoadingMore || !_hasMoreMessages) return;
        _isLoadingMore = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(_activeChannelId, _skip, PageSize);
        if (older.Count < PageSize) _hasMoreMessages = false;
        _messages.InsertRange(0, older);
        _skip += older.Count;
        _isLoadingMore = false;

        await RefreshThreadCounts();
    }

    private async Task SendMessage(string content)
    {
        var msg = await ChatService.SendMessageAsync(_activeChannelId, content, null);
        _messages.Add(msg);
        _skip++;
    }

    private async Task HandleReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        // Refresh the affected message's reactions by reloading visible messages
        var updated = await ChatService.GetMessagesAsync(_activeChannelId, 0, _skip);
        _messages = updated;
    }

    private async Task OpenThread(int rootMessageId)
    {
        _threadRootMessage = _messages.FirstOrDefault(m => m.Id == rootMessageId);
        if (_threadRootMessage is null) return;

        _threadReplies = await ChatService.GetThreadAsync(rootMessageId);
    }

    private void CloseThread()
    {
        _threadRootMessage = null;
        _threadReplies = null;
    }

    private async Task SendThreadReply(string content)
    {
        if (_threadRootMessage is null) return;
        var reply = await ChatService.SendMessageAsync(
            _activeChannelId, content, _threadRootMessage.Id);
        _threadReplies ??= new();
        _threadReplies.Add(reply);

        // Update thread reply count
        _threadReplyCounts[_threadRootMessage.Id] =
            _threadReplyCounts.GetValueOrDefault(_threadRootMessage.Id) + 1;
    }

    private async Task RefreshThreadCounts()
    {
        // Build thread counts from messages that have replies pointing to them
        var rootIds = _messages
            .Where(m => m.ReplyToId is null)
            .Select(m => m.Id)
            .ToHashSet();

        foreach (var rootId in rootIds)
        {
            if (!_threadReplyCounts.ContainsKey(rootId))
            {
                var thread = await ChatService.GetThreadAsync(rootId);
                if (thread.Count > 0)
                {
                    _threadReplyCounts[rootId] = thread.Count;
                }
            }
        }
    }

    private async Task RefreshChannels()
    {
        _channels = await ChatService.GetChannelsAsync();
    }
}

.chat-container {
    display: flex;
    height: 100vh;
    width: 100%;
    overflow: hidden;
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, 'Helvetica Neue', Arial, sans-serif;
}

.chat-sidebar {
    width: 20%;
    min-width: 200px;
    max-width: 280px;
    flex-shrink: 0;
}

.chat-main {
    flex: 1;
    min-width: 0;
}

.chat-main-expanded {
    flex: 1;
}

.chat-thread {
    width: 25%;
    min-width: 280px;
    max-width: 400px;
    flex-shrink: 0;
}

window.chatInterop = {
    scrollToBottom: function (element) {
        if (element) {
            element.scrollTop = element.scrollHeight;
        }
    },
    getScrollTop: function (element) {
        return element ? element.scrollTop : 0;
    }
};

